// apiService.js

const BASE_URL = 'https://api.example.com';

// Token storage (in-memory; in production, use AsyncStorage or secure storage)
let authToken = null;
let refreshToken = null;

// ============================================================
// Token Management
// ============================================================

const setTokens = (access, refresh) => {
  authToken = access;
  refreshToken = refresh;
};

const getAuthToken = () => authToken;

const clearTokens = () => {
  authToken = null;
  refreshToken = null;
};

// ============================================================
// Request Helper
// ============================================================

const buildHeaders = (customHeaders = {}, includeAuth = true) => {
  const headers = {
    'Content-Type': 'application/json',
    Accept: 'application/json',
    ...customHeaders,
  };

  if (includeAuth && authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  return headers;
};

const handleResponse = async (response) => {
  const contentType = response.headers.get('content-type');
  let data;

  if (contentType && contentType.includes('application/json')) {
    data = await response.json();
  } else {
    data = await response.text();
  }

  if (!response.ok) {
    const error = new Error(data?.message || data?.error || `HTTP Error ${response.status}`);
    error.status = response.status;
    error.data = data;
    throw error;
  }

  return data;
};

const request = async (endpoint, options = {}, retry = true) => {
  const {
    method = 'GET',
    body = null,
    headers = {},
    includeAuth = true,
    timeout = 15000,
  } = options;

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeout);

  try {
    const fetchOptions = {
      method,
      headers: buildHeaders(headers, includeAuth),
      signal: controller.signal,
    };

    if (body && method !== 'GET') {
      fetchOptions.body = JSON.stringify(body);
    }

    const response = await fetch(`${BASE_URL}${endpoint}`, fetchOptions);

    // If 401 and we have a refresh token, attempt token refresh and retry once
    if (response.status === 401 && refreshToken && retry) {
      const refreshed = await attemptTokenRefresh();
      if (refreshed) {
        return request(endpoint, options, false);
      } else {
        clearTokens();
        throw new Error('Session expired. Please log in again.');
      }
    }

    return await handleResponse(response);
  } catch (error) {
    if (error.name === 'AbortError') {
      throw new Error('Request timed out. Please check your connection and try again.');
    }
    throw error;
  } finally {
    clearTimeout(timeoutId);
  }
};

// ============================================================
// Token Refresh
// ============================================================

const attemptTokenRefresh = async () => {
  try {
    const response = await fetch(`${BASE_URL}/auth/refresh`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
      body: JSON.stringify({ refresh_token: refreshToken }),
    });

    if (!response.ok) {
      return false;
    }

    const data = await response.json();
    setTokens(data.access_token, data.refresh_token || refreshToken);
    return true;
  } catch {
    return false;
  }
};

